<?php
namespace App\Http\Controllers;
use App\Enums\LockerStatus; use App\Enums\PrintOrderStatus; use App\Jobs\ClosePickupLockerJob; use App\Models\PrintOrder; use App\Services\Esp32DeviceService; use App\Services\OrderStatusService; use App\Services\PickupCodeService; use Illuminate\Http\RedirectResponse; use Illuminate\Http\Request; use Illuminate\Support\Facades\DB; use Illuminate\Validation\ValidationException; use Inertia\Inertia; use Inertia\Response;
class PickupController extends Controller { public function create():Response{return Inertia::render('pickup');} public function store(Request $request,PickupCodeService $codes,Esp32DeviceService $device,OrderStatusService $statuses):RedirectResponse{$code=$request->validate(['code'=>['required','digits:6']])['code'];$order=PrintOrder::where('status',PrintOrderStatus::ReadyForPickup)->get()->first(fn($o)=>$codes->verify($code,$o->pickup_code_hash));if(!$order)return back()->withErrors(['code'=>'That pickup code is invalid, expired, or already used.']);DB::transaction(function()use($order,$device,$statuses){$order=PrintOrder::lockForUpdate()->findOrFail($order->id);if($order->status!==PrintOrderStatus::ReadyForPickup)throw ValidationException::withMessages(['code'=>'This code has already been used.']);$device->openPickupDoor($order);$order->locker()->update(['status'=>LockerStatus::Opening]);$statuses->transition($order,PrintOrderStatus::OpeningLocker,'Locker door opened.');});ClosePickupLockerJob::dispatch($order->id)->delay(now()->addSeconds(config('queueless.locker_open_seconds')));return to_route('orders.show',$order->public_reference)->with('success',"Locker {$order->locker->locker_number} is now open. Please collect your document. The door will close automatically in ".config('queueless.locker_open_seconds').' seconds.');} }
